mapper.select:
SELECT d.*,
       (SELECT COUNT(*) FROM drug_subscription ds WHERE ds.drug_id = d.id) AS subscription_count
FROM drug d


        AND d.id = #{id}


        AND d.name LIKE concat('%',#{name},'%')


        AND d.category = #{category}


        AND d.is_otc = #{isOtc}


        AND d.status = #{status}


ORDER BY d.id DESC

    LIMIT #{current},#{size}

SELECT COUNT(*)
FROM drug d


        AND d.id = #{id}


        AND d.name LIKE concat('%',#{name},'%')


        AND d.category = #{category}


        AND d.is_otc = #{isOtc}


        AND d.status = #{status}
